$fn = 100;

module tortoise_shell_pattern() {
    for (i = [0:10:360]) {
        rotate([0, 0, i])
        translate([torus_minor_radius, 0, 0])
        cube([2, 2, 2], center = true);
    }
}

module tortoise_torus() {
    color([0.4, 0.2, 0.05])
    rotate_extrude()
    translate([torus_major_radius, 0, 0])
    tortoise_shell_pattern();
}

module gold_disk() {
    color([1, 0.84, 0])
    cylinder(r = disk_radius, h = disk_thickness);
}

module white_rod() {
    color([1, 1, 1])
    cylinder(r = rod_radius, h = rod_length);
}

module gray_wires() {
    color([0.5, 0.5, 0.5])
    for (i = [0:wire_count-1]) {
        rotate([0, 0, i * (360/wire_count)])
        translate([torus_major_radius, 0, 0])
        rotate([0, 90, 0])
        cylinder(r = wire_radius, h = disk_radius + 5);
    }
}

union() {
    translate([0, 0, -disk_thickness - rod_length])
    gold_disk();

    translate([0, 0, -rod_length])
    tortoise_torus();

    white_rod();

    gray_wires();
}

core_radius = 10;
core_height = 40;
ring_thickness = 4;
ring_radius = 25;
base_radius = 30;
base_height = 5;
num_rings = 4;

module hollow_core() {
    difference() {
        cylinder(r = core_radius + ring_thickness, h = core_height, $fn = 64);
        translate([0, 0, -1]) cylinder(r = core_radius, h = core_height + 2, $fn = 64);
    }
}

module ring_structure() {
    for (i = [0 : num_rings - 1]) {
        rotate([0, 0, i * (360 / num_rings)])
        translate([core_radius + ring_thickness + ring_radius / 2, 0, core_height / 2])
        rotate([0, 90, 0])
        cylinder(r = ring_radius, h = ring_thickness, $fn = 64);
    }
}

union() {
    hollow_core();
    translate([0, 0, -base_height]) cylinder(r = base_radius, h = base_height, $fn = 64);
    ring_structure();
}

base_radius = 50;
base_thickness = 5;
cone_radius = 30;
cone_height = 60;
bolt_hole_radius = 4;
bolt_spacing = 20;
ring_radius = 35;
ring_thickness = 4;
ring_bolt_offset = 15;

$fn = 100;

union() {
    difference() {
        cylinder(r = base_radius, h = base_thickness);

        for (i = [0 : 3]) {
            rotate([0, 0, i * 90])
            translate([base_radius - 5, 0, base_thickness - 1])
            cylinder(r = bolt_hole_radius, h = 10);
        }
    }

    translate([0, 0, base_thickness])
    cylinder(r1 = cone_radius, r2 = 5, h = cone_height);

    translate([0, 0, base_thickness + cone_height])
    difference() {
        cylinder(r = ring_radius, h = ring_thickness);

        cylinder(r = cone_radius, h = ring_thickness);

        translate([0, 0, -1])
        cylinder(r = ring_radius - ring_bolt_offset, h = ring_thickness + 2);
    }
}

sphere_radius = 10;
prism_side = 8;
prism_height = 15;
rect_size = [12, 12, 12];
cyl_radius = 6;
cyl_height = 20;

$fn = 100;

union() {
    // Sphere
    translate([-20, 0, 0])
    sphere(r = sphere_radius);

    // Pentagonal Prism
    translate([20, 0, 0])
    rotate([0, 0, 0])
    cylinder(r = prism_side, h = prism_height, $fn = 5);

    // Rectangular Prism
    translate([0, 20, 0])
    cube(rect_size, center = true);

    // Cylindrical shape
    translate([0, -20, 0])
    rotate([90, 0, 0])
    cylinder(r = cyl_radius, h = cyl_height);
}

clamp_radius = 20;
clamp_height = 40;
rail_width = 10;
rail_length = 60;
bolt_radius = 5;
bolt_length = 50;
nut_size = 8;

color([0.1, 0.1, 0.1]) {
    // Main Clamp Body
    difference() {
        cylinder(r = clamp_radius, h = clamp_height, $fn = 64);
        translate([0, 0, 5])
            cylinder(r = clamp_radius - 2, h = clamp_height, $fn = 64);
    }

    // Ratcheted Rail
    translate([0, 0, clamp_height])
    difference() {
        cube([rail_length, rail_width, 5], center = true);
        for (i = [0:5:rail_length-5]) {
            translate([i, 0, 0])
                cube([2, rail_width, 2], center = true);
        }
    }

    // Threaded Bolt
    translate([clamp_radius - 2, 0, clamp_height / 2])
    rotate([0, 90, 0])
    union() {
        cylinder(r = bolt_radius, h = bolt_length, $fn = 32);

        // Label
        translate([0, 0, 15])
            cube([bolt_radius * 2, 2, 10], center = true);

        // Hex Nut
        translate([0, 0, bolt_length])
            cylinder(r = nut_size / 1.732, h = 4, $fn = 6);
    }
}

rod_radius = 5;
rod_height = 100;
shaft_radius = 3;
shaft_length = 40;
joint_radius = 12;
extension_radius = 4;
extension_length = 15;

union() {
    // Central vertical rod
    cylinder(r = rod_radius, h = rod_height, $fn = 50);

    // Horizontal shaft
    translate([0, 0, rod_height / 2])
    rotate([0, 90, 0])
    cylinder(r = shaft_radius, h = shaft_length, $fn = 30);

    // Three spherical joints
    for (i = [0:2]) {
        angle = i * 120;
        translate([
            cos(angle) * (rod_height / 2 + joint_radius / 2),
            sin(angle) * (rod_height / 2 + joint_radius / 2),
            rod_height / 2
        ]) {
            // Spherical joint
            sphere(r = joint_radius, $fn = 50);

            // Two perpendicular cylindrical extensions
            for (j = [0:1]) {
                rotate([0, 0, angle + (j * 90)])
                translate([0, 0, joint_radius])
                cylinder(r = extension_radius, h = extension_length, $fn = 20);
            }
        }
    }
}
